"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const stops=[["Frame","Set the reader’s starting context."],["Inspect","Pause on the clearest evidence."],["Act","Record the next reversible action."]];
export default function ReadingWindowRail(){const [active,setActive]=useState(0);const reduced=useReducedMotion();return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><div className="flex gap-4"><div aria-hidden className="relative h-40 w-5 rounded-full bg-[#f4f5f6]"><motion.i className="absolute left-0 h-8 w-5 rounded-xl bg-[#ff9950]" animate={{top:active*52+4}} transition={reduced?{duration:0}:{type:"spring",stiffness:315,damping:26}}/></div><div className="flex-1"><p className="text-xs font-extrabold uppercase tracking-[.14em] text-[#4a4a4f]">reading window</p><motion.div key={active} initial={{opacity:0}} animate={{opacity:1}} transition={{duration:reduced?.12:.15}} className="mt-3"><strong className="text-[#111]">{stops[active][0]}</strong><p className="mt-1 text-sm text-[#4a4a4f]">{stops[active][1]}</p></motion.div><div aria-label="Reading checkpoint" className="mt-4 grid gap-2">{stops.map((stop,i)=><button key={stop[0]} type="button" aria-pressed={active===i} onClick={()=>setActive(i)} className="min-h-11 rounded-xl border border-[#ececee] bg-white px-3 text-left text-sm font-bold text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{i+1}. {stop[0]}</button>)}</div></div></div><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">Reading checkpoint {active+1} of 3: {stops[active][0]}.</p></section>}
